// // This module is designed to select the second input when the select signal is high
module mux_16bit (  
    input [15:0] A,  
    input [15:0] B,  
    input sel,  
    output reg [15:0] Y  
);  
    always @(*) begin  
        if (sel)  
            Y = B;  
        else  
            Y = A;  
    end  
endmodule
